  "inlineSchema": "// Prisma Schema for AI Native App\n// Better Auth + PostgreSQL (Neon)\n\ngenerator client {\n  provider        = \"prisma-client\"\n  previewFeatures = [\"postgresqlExtensions\"]\n  output          = \"../src/app/generated/prisma\"\n}\n\ndatasource db {\n  provider   = \"postgresql\"\n  extensions = [pgvector(map: \"vector\")]\n}\n\n// ==========================================\n// Better Auth Core Schema\n// ==========================================\n\nmodel User {\n  id               String    @id @default(cuid())\n  name             String\n  email            String    @unique\n  emailVerified    Boolean   @default(false)\n  image            String?\n  role             String    @default(\"user\") // \"user\" | \"admin\"\n  banned           Boolean?\n  banReason        String?\n  banExpires       DateTime?\n  twoFactorEnabled Boolean?  @default(false) // ← เพิ่มใหม่\n  createdAt        DateTime  @default(now())\n  updatedAt        DateTime  @updatedAt\n\n  sessions   Session[]\n  accounts   Account[]\n  twoFactors TwoFactor[] // ← เพิ่มใหม่\n\n  @@map(\"user\")\n}\n\nmodel Session {\n  id             String   @id @default(cuid())\n  userId         String\n  token          String   @unique\n  expiresAt      DateTime\n  ipAddress      String?\n  userAgent      String?\n  impersonatedBy String?\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"session\")\n}\n\nmodel Account {\n  id                    String    @id @default(cuid())\n  userId                String\n  accountId             String\n  providerId            String\n  accessToken           String?\n  refreshToken          String?\n  accessTokenExpiresAt  DateTime?\n  refreshTokenExpiresAt DateTime?\n  scope                 String?\n  idToken               String?\n  password              String?\n  createdAt             DateTime  @default(now())\n  updatedAt             DateTime  @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"account\")\n}\n\nmodel Verification {\n  id         String    @id @default(cuid())\n  identifier String\n  value      String\n  expiresAt  DateTime\n  createdAt  DateTime? @default(now())\n  updatedAt  DateTime? @updatedAt\n\n  @@map(\"verification\")\n}\n\n// ==========================================\n// Better Auth Two-Factor Plugin\n// ==========================================\n\nmodel TwoFactor {\n  id          String   @id @default(cuid())\n  userId      String\n  secret      String\n  backupCodes String\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  user User @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  @@map(\"twoFactor\")\n}\n\nmodel Document {\n  id        String                       @id @default(cuid())\n  content   String // เนื้อหาข้อความ\n  metadata  Json? // ข้อมูลเพิ่มเติม (เช่น ชื่อไฟล์, หน้า)\n  embedding Unsupported(\"vector(1536)\")? // เวกเตอร์จาก OpenAI (1536 มิติ)\n  createdAt DateTime                     @default(now())\n  updatedAt DateTime                     @updatedAt\n\n  @@map(\"document\")\n}\n\n// ==========================================\n// Chat Session & Message Schema สำหรับ Chat History\n// ==========================================\nmodel ChatSession {\n  id        String        @id @default(cuid())\n  userId    String\n  title     String?\n  createdAt DateTime      @default(now())\n  updatedAt DateTime      @updatedAt\n  messages  ChatMessage[]\n\n  @@map(\"chat_session\")\n}\n\nmodel ChatMessage {\n  id        String   @id @default(cuid())\n  sessionId String\n  role      String // \"user\" | \"assistant\"\n  content   String\n  sources   Json? // แหล่งข้อมูลอ้างอิง\n  createdAt DateTime @default(now())\n\n  session ChatSession @relation(fields: [sessionId], references: [id], onDelete: Cascade)\n\n  @@map(\"chat_message\")\n}\n\n// ==========================================\n// Knowledge Base Management\n// ==========================================\nmodel KnowledgeDocument {\n  id        String   @id @default(cuid())\n  title     String\n  content   String   @db.Text\n  source    String? // ชื่อไฟล์ต้นฉบับ (ถ้าอัปโหลด)\n  fileType  String? // \"pdf\" | \"csv\" | \"txt\" | \"manual\"\n  fileSize  Int? // ขนาดไฟล์ (bytes)\n  isIndexed Boolean  @default(false) // ถูก process เข้า Vector DB แล้วหรือยัง\n  createdBy String // userId ของผู้สร้าง\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"knowledge_document\")\n}\n\n// ==========================================\n// Lead Capture Table\n// ==========================================\nmodel Lead {\n  id        String   @id @default(cuid())\n  name      String\n  email     String\n  phone     String?\n  company   String?\n  interest  String?\n  source    String   @default(\"website\")\n  status    String   @default(\"new\") // new, contacted, qualified, converted\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@map(\"lead\")\n}\n\n// ==========================================\n// LINE Group Registration Table\n// ==========================================\nmodel LineGroup {\n  id        String   @id @default(cuid())\n  groupId   String   @unique // LINE Group ID (เช่น Cf224170d...)\n  groupName String? // ชื่อกลุ่ม (ดึงจาก LINE API)\n  active    Boolean  @default(true) // true = ส่งแจ้งเตือน, false = หยุดส่ง\n  joinedAt  DateTime @default(now()) // วันที่ Bot เข้ากลุ่ม\n  updatedAt DateTime @updatedAt\n\n  @@map(\"line_group\")\n}\n",
